/**
 * Sets spanning several days (one week of one exercise), grouped by day. Each
 * day is a header row above that day's sets, so the date sits "up top" instead
 * of repeating in its own column — matching the Workouts view.
 */
function setsByDateTableHtml(sets: readonly SetRecord[]): string {
  const formula = currentFormula();
  const strengthByDay = currentStrengthByUserExercise(formula);
  const byDate = new Map<string, SetRecord[]>();
  for (const s of sets) {
    const g = byDate.get(s.date);
    if (g) g.push(s);
    else byDate.set(s.date, [s]);
  }
  const body = Array.from(byDate, ([date, daySets]) => {
    const header = `<tr class="set-date-row"><td colspan="5" class="wo-date">${shortDate(date)}</td></tr>`;
    return header + daySets.map((s) => setRowsHtml(s, formula, currentStrengthFor(strengthByDay, s))).join("");
  }).join("");
  return `<table class="data-table detail-table">${setsHead()}<tbody>${body}</tbody></table>`;
}

/** Best / latest / trend summary line for an exercise's day-by-day 1RM series.
 * Shown under the per-exercise drill-in chart. */




// ---- Exercises tab: which spellings were merged into one lift ----
// Documents every combine (per the owner's rule that merges must be visible),
// newest list straight from the canonicaliser. Empty state when nothing merged.
function renderMergeList() {
  const merges = data.merges;
  if (!merges.length) {
    els.mergeList.innerHTML = `<p class="muted">No exercises needed combining — every lift is logged under one name.</p>`;
    return;
  }
  const head = `<thead><tr><th>Shown as</th><th>Combined from</th><th class="num">Sets</th></tr></thead>`;
  const body = merges
    .map(
      (m) =>
        `<tr><td>${escapeHtml(m.canonical)}</td>` +
        `<td>${m.variants.map((v) => escapeHtml(v)).join(", ")}</td>` +
        `<td class="num">${m.sets.toLocaleString()}</td></tr>`,
    )
    .join("");
  els.mergeList.innerHTML = `<table class="data-table">${head}<tbody>${body}</tbody></table>`;
}

/**
 * The app-wide active-set control on the Index page: a frequency-tier cutoff that
 * hides every lift below it everywhere in the app (default None = show all). The
 * per-exercise include/exclude overrides get inline toggles in a later slice; for
 * now the cutoff is the lever, and any manual overrides are summarised + clearable.
 */
/** Every distinct value a dimension takes across all logged exercises, sorted. */
function distinctMetaValues(dim: ExerciseFilterDim): string[] {
  const seen = new Set<string>();
  for (const name of new Set(data.records.map((r) => r.exerciseName))) {
    if (!name) continue;
    for (const v of waMeta(name, dim)) if (v) seen.add(v);
  }
  return [...seen].sort((a, b) => a.localeCompare(b));
}

function renderActiveSetBar(totalExercises: number): void {
  const active = activeSet ? activeSet.size : totalExercises;
  const hidden = Math.max(0, totalExercises - active);
  // Spell out WHY lifts are hidden (frequency tiers / a picked "only these" set /
  // taxonomy filters / manual overrides) so the filter is never a mystery, and give
  // ONE obvious escape hatch that turns the whole thing off.
  let status: string;
  let reset = "";
  if (activeSet) {
    const why: string[] = [];
    if (activeSolo) why.push("a picked “only these” set");
    if (activeFreqTiers.size) why.push(`frequency ${[...activeFreqTiers].join("/")}`);
    for (const f of activeMetaFilterList()) why.push(`${FILTER_DIM_LABELS[f.dim].toLowerCase()}: ${f.values.join("/")}`);
    if (activeInclude.size) why.push(`${activeInclude.size} forced-in`);
    if (activeExclude.size) why.push(`${activeExclude.size} forced-out`);
    status =
      `<span class="as-status is-on">Showing ${active} of ${totalExercises} — <strong>${hidden} hidden</strong>` +
      (why.length ? ` <span class="as-why">(${escapeHtml(why.join(" · "))})</span>` : "") + `</span>`;
    reset = ` <button type="button" class="as-clear as-reset" data-asreset="1">Show all ${totalExercises} (clear the filter)</button>`;
  } else {
    status = `<span class="as-status muted">Showing all ${totalExercises} exercises (filter off)</span>`;
  }
  // Pick a CATEGORY (Frequency + every taxonomy dim); its value pills toggle that
  // category's accepted values. Stack as many categories as you like — chips below
  // show them all and they AND together (OR within one category).
  // A filter row = a category picker + its value-pills. Two are shown (stackable, AND).
  const filterRow = (dim: GreatFilterDim, idx: number): string => {
    const dimOpts = GREAT_FILTER_DIMS
      .map((d) => `<option value="${d}"${d === dim ? " selected" : ""}>${escapeHtml(GREAT_FILTER_LABELS[d])}</option>`)
      .join("");
    const valuePills = dim === "frequency"
      ? FREQ_TIERS.map((t) => { const on = activeFreqTiers.size === 0 || activeFreqTiers.has(t.tier); return `<button type="button" class="as-fpill${on ? " is-on" : ""}" data-asfdim="frequency" data-asfval="${t.tier}" aria-pressed="${on}">${escapeHtml(t.label)}</button>`; }).join("")
      : (() => {
          const chosen = new Set(activeMetaFilters[dim as ExerciseFilterDim] ?? []);
          const allOn = chosen.size === 0; // nothing chosen → every value passes → show all ON
          return distinctMetaValues(dim as ExerciseFilterDim)
            .map((v) => { const on = allOn || chosen.has(v); return `<button type="button" class="as-fpill${on ? " is-on" : ""}" data-asfdim="${escapeHtml(dim)}" data-asfval="${escapeHtml(v)}" aria-pressed="${on}">${escapeHtml(v)}</button>`; })
            .join("");
        })();
    const pillsRow = valuePills ? `<div class="as-fpills">${valuePills}</div>` : `<div class="as-fpills muted as-fnone">no values</div>`;
    return `<div class="as-filter-row"><label class="as-label">Filter by <select class="subtle-select as-dim-sel" data-fidx="${idx}">${dimOpts}</select></label>${pillsRow}</div>`;
  };
  // "Kept exceptions" manager: every lift you force-SHOW (or force-hide) despite the
  // filter, listed and removable — so exceptions never pile up invisibly. (The right fix
  // for most hidden lifts is to correct their tags, not keep them; this tracks the rest.)
  const excChips = (set: Set<string>, kind: "include" | "exclude", verb: string) =>
    [...set].map((n) => `<button type="button" class="as-exc-chip as-exc-${kind}" data-asexc="${escapeHtml(n)}" data-asexckind="${kind}" title="${verb} — tap ✕ to remove">${escapeHtml(displayName(n))} ✕</button>`).join("");
  const exceptionsRow = (activeInclude.size || activeExclude.size)
    ? `<details class="as-exceptions"${asExceptionsOpen ? " open" : ""}>` +
      `<summary class="as-exc-sum">⚑ Exceptions: ${activeInclude.size} kept${activeExclude.size ? ` · ${activeExclude.size} forced-out` : ""}</summary>` +
      `<div class="as-exc-list">${excChips(activeInclude, "include", "Force-shown")}${excChips(activeExclude, "exclude", "Force-hidden")}` +
      `<button type="button" class="as-clear" data-asclear="1">clear all exceptions</button></div></details>`
    : "";
  els.activeSetBar.innerHTML =
    `<div class="as-title">The Great Filter</div>` +
    `<div class="as-statusrow">${status}${reset}</div>` +
    exceptionsRow +
    activeFilterDims.map((d, i) => filterRow(d, i)).join("") +
    `<p class="as-hint muted">Restricts the WHOLE app — every list, graph, leaderboard, and the Index below. Each row is a category; tap values to keep only those. Rows stack (they AND together; any value within one row passes). “Show all” clears every filter at once.</p>`;
}

/** Cutoff dropdown changed: save + re-render the whole app. */
/** Clear all manual include/exclude overrides (keeps the category filters). */
function clearActiveOverrides(): void {
  activeInclude = new Set();
  activeExclude = new Set();
  activeSolo = null;
  saveActiveSet();
  scheduleRender();
}

/** Turn the WHOLE app-wide filter OFF in one tap — tier, taxonomy filters, the
 * "only these" solo set and every manual override — so every lift shows again.
 * The one escape hatch when "where did my lift go?". */
function resetActiveSetAll(): void {
  activeCutoff = null;
  activeFreqTiers = new Set();
  activeInclude = new Set();
  activeExclude = new Set();
  activeSolo = null;
  activeMetaFilters = {};
  saveActiveSet();
  scheduleRender();
}

/** Re-render just the app-wide active-set bar (used when only the displayed filter
 * dimension changes — no app-wide data change). */
function rerenderActiveSetBar(): void {
  const total = new Set(data.records.map((r) => r.exerciseName).filter(Boolean)).size;
  renderActiveSetBar(total);
}

/** Toggle one taxonomy value for a dimension in the app-wide filter (OR within the
 * dim, AND across dims), then re-apply app-wide. */
function toggleActiveMetaValue(dim: GreatFilterDim, value: string): void {
  // A row with NOTHING chosen means ALL values pass (every pill shown ON). So the FIRST
  // tap from that state DESELECTS the tapped value (keep the rest); further taps toggle;
  // and if every value ends up chosen again it resets to "all" (no filter).
  const all = dim === "frequency" ? FREQ_TIERS.map((t) => t.tier) : distinctMetaValues(dim as ExerciseFilterDim);
  const cur = new Set<string>(dim === "frequency" ? activeFreqTiers : (activeMetaFilters[dim] ?? []));
  let next: Set<string>;
  if (cur.size === 0) next = new Set(all.filter((v) => v !== value));
  else { next = new Set(cur); if (next.has(value)) next.delete(value); else next.add(value); }
  if (next.size >= all.length) next = new Set();
  if (dim === "frequency") activeFreqTiers = next;
  else if (next.size) activeMetaFilters[dim] = [...next];
  else delete activeMetaFilters[dim];
  saveActiveSet();
  scheduleRender();
}

/** Clear every app-wide category filter — Frequency + taxonomy (keeps overrides). */
function clearActiveMetaFilters(): void {
  activeMetaFilters = {};
  activeFreqTiers = new Set();
  saveActiveSet();
  scheduleRender();
}

/** Toggle one exercise's force-IN (include) or force-OUT (exclude) override from
 * the Index inspector, then re-apply app-wide and re-open the inspector row. */
function toggleActiveOverride(name: string, which: "include" | "exclude"): void {
  if (which === "include") {
    if (activeInclude.has(name)) activeInclude.delete(name);
    else { activeInclude.add(name); activeExclude.delete(name); }
  } else {
    if (activeExclude.has(name)) activeExclude.delete(name);
    else { activeExclude.add(name); activeInclude.delete(name); }
  }
  saveActiveSet();
  renderAll();
  reopenIndexDetail(name);
}

/** After an app-wide re-render, keep the exercise-settings overlay in sync (it
 * lives outside the rebuilt table, so it survives — just refresh its content if
 * it's showing this lift). Used by the in-overlay edit toggles. */
function reopenIndexDetail(name: string): void {
  if (currentExInfo === name) refreshExerciseInfo();
}

/** Open every <details> ancestor of an element (so a row tucked inside the Index
 * "Show hidden" sub-dropdown becomes visible, not just its group). */
function openAncestorDetails(el: HTMLElement): void {
  for (let p = el.parentElement; p; p = p.parentElement)
    if (p instanceof HTMLDetailsElement) p.open = true;
}

/** The editable middle cell of an Index row, for whichever attribute the quick-edit
 * picker has chosen. BW part stays a number input. Tier, discipline & muscle group are
 * all a compact single-pick .xdd dropdown MENU (auto-enhanced, rule 20) — tier keeps
 * its colour and adds an "↺ Auto" option to drop the override. Each sets the override
 * for THIS lift. */
function indexEditCell(r: IndexRow): string {
  if (indexEditAttr === "coeff")
    return `<input class="bw-input" type="number" step="0.05" min="0" max="2" value="${r.coeff}" ` +
      `data-ex="${escapeHtml(r.name)}" aria-label="Bodyweight part for ${escapeHtml(r.name)}" />`;
  const name = r.name;
  const kind = indexEditAttr; // "tier" | "disc" | "mg"
  const overridden = metaSet(kind, name) != null;
  if (kind === "tier") {
    const t = tiersFor(name)[0]!;
    // A real menu (auto-enhanced to our .xdd, rule 20), not a cycling pill — tap to
    // pick the tier directly, with ↺ Auto to drop the override. Coloured by the
    // current tier via its `tier-<t>` class (carried onto the .xdd twin).
    const opts = TIER_RANK
      .map((v) => `<option value="${v}"${v === t ? " selected" : ""}>${escapeHtml(TIER_LABELS[v])}</option>`)
      .join("") + `<option value="auto">↺ Auto</option>`;
    return `<select class="bw-attr-edit subtle-select tier-${t}${overridden ? " is-overridden" : ""}" ` +
      `data-attrex="${escapeHtml(name)}" data-attrkind="tier" style="--tier-c:${TIER_COLORS[t]}" ` +
      `aria-label="Tier for ${escapeHtml(name)}">${opts}</select>`;
  }
  const cur = kind === "disc" ? discsFor(name)[0]! : mgsFor(name)[0]!;
  const values: readonly string[] = kind === "disc" ? DISCIPLINES : MUSCLE_GROUPS;
  const opts = values
    .map((v) => `<option value="${escapeHtml(v)}"${v === cur ? " selected" : ""}>${escapeHtml(v)}</option>`)
    .join("");
  return `<select class="bw-attr-edit subtle-select${overridden ? " is-overridden" : ""}" ` +
    `data-attrex="${escapeHtml(name)}" data-attrkind="${kind}" ` +
    `aria-label="${escapeHtml(INDEX_EDIT_ATTRS.find((a) => a.attr === kind)!.label)} for ${escapeHtml(name)}">${opts}</select>`;
}

// ---- BW parts tab: every exercise and its bodyweight coefficient ----
// Freeze the Index grouping so editing a lift's TAG (tier / discipline / muscle /
// group) doesn't make its row JUMP to the new bucket mid-edit — disorienting when you're
// retagging a few lifts in a row. The rendered layout is cached and reused, so the
// order only re-sorts on a real refresh: a page reload, switching the grouping MODE
// (cache is mode-keyed), or the set of lifts changing (count-keyed). Owner request.
let indexLayoutFreeze:
  | { mode: IndexGroupMode; total: number; buckets: { key: string; label: string; color: string; names: string[] }[] }
  | null = null;
function renderBwParts() {
  renderMergeList();
  const createBox = document.getElementById("idxCreate");
  if (createBox) createBox.innerHTML = createVariantFormHtml();
  const counts = new Map<string, number>();
  for (const r of data.records) if (r.exerciseName) counts.set(r.exerciseName, (counts.get(r.exerciseName) ?? 0) + 1);

  const rows: IndexRow[] = [...counts.keys()]
    .map((name) => ({ name, coeff: coeffFor(name), count: counts.get(name)! }));
  // Synthetic combined/comparable lifts are first-class exercises too: list them
  // alongside their members (set count = the members' sets summed) so they appear in
  // every grouping. Only when at least one member is actually trained.
  for (const g of [...effectiveCombinableGroups(), ...effectiveComparableGroups()]) {
    const dn = g.derivedName ?? g.label;
    if (counts.has(dn)) continue; // already a logged name (shouldn't happen for synthetics)
    const present = (g.members ?? []).map((m) => m.exerciseName).filter((m) => counts.has(m));
    if (!present.length) continue;
    rows.push({ name: dn, coeff: coeffFor(dn), count: present.reduce((n, m) => n + (counts.get(m) ?? 0), 0) });
  }
  // Most-trained first (by set count), then alphabetical - kept inside each group.
  rows.sort((a, b) => b.count - a.count || a.name.localeCompare(b.name));

  els.bwTitle.textContent = "Index";
  renderActiveSetBar(rows.length);
  renderBwGroupBar();

  // Slice the same rows into the chosen grouping (category / muscle / function /
  // combinable / comparable). Frozen layout (see indexLayoutFreeze): reuse the cached
  // bucket order/membership so a tag edit doesn't re-sort; recompute fresh (and re-cache)
  // only when the mode or the lift set changed (or on reload).
  let buckets: IndexBucket[];
  if (indexLayoutFreeze && indexLayoutFreeze.mode === S.bwGroupMode && indexLayoutFreeze.total === rows.length) {
    const rowByName = new Map(rows.map((r) => [r.name, r] as const));
    buckets = indexLayoutFreeze.buckets
      .map((b) => ({ key: b.key, label: b.label, color: b.color, rows: b.names.map((n) => rowByName.get(n)).filter((r): r is IndexRow => !!r) }))
      .filter((b) => b.rows.length);
  } else {
    buckets = indexBuckets(rows, S.bwGroupMode);
    indexLayoutFreeze = { mode: S.bwGroupMode, total: rows.length, buckets: buckets.map((b) => ({ key: b.key, label: b.label, color: b.color, names: b.rows.map((r) => r.name) })) };
  }
  // When grouped by COMPARABLE, each group's rows show their scaling ratio in that group
  // (and the reference lift, ratio 1, is tagged "étalon"). Build a per-group lookup once.
  const compRatioByGroup = S.bwGroupMode === "comparable"
    ? new Map(effectiveComparableGroups().map((g) => [g.id, new Map((g.members ?? []).map((m) => [m.exerciseName, m.ratio] as const))]))
    : null;

  // Remember which groups the user has opened, so editing/re-rendering keeps them
  // as they were. Groups start collapsed by default (empty set on first paint);
  // afterwards we read the live open/closed state back out of the DOM.
  if (S.bwOpenCats === null) S.bwOpenCats = new Set<string>();
  else {
    S.bwOpenCats = new Set<string>();
    for (const d of els.bwGroups.querySelectorAll<HTMLDetailsElement>("details.bw-cat"))
      if (d.open && d.dataset.cat) S.bwOpenCats.add(d.dataset.cat);
  }
  const open = (cat: string) => S.bwOpenCats!.has(cat);

  const editLabel = INDEX_EDIT_ATTRS.find((a) => a.attr === indexEditAttr)!.label;
  const head = `<thead><tr><th>Exercise</th><th class="num">${escapeHtml(editLabel)}</th><th class="num">Sets</th></tr></thead>`;
  // One row's <tr>, reused for both shown and (greyed) hidden-by-filter lists.
  const rowHtml = (r: IndexRow, hidden: boolean, ratioOf?: (name: string) => number | null, refEx?: string | null) => {
    // On a filtered-out row: show WHY (the failing filter + this lift's value) as a red
    // chip that opens the tag editor — most hidden lifts are mis-tagged, not unwanted,
    // so the fix is to correct the tag, not force an exception.
    const reasons = hidden ? hiddenReasons(r.name) : [];
    const whyChip = reasons.length
      ? ` <button type="button" class="bw-why" data-moreinfoex="${escapeHtml(r.name)}" title="Filtered out — ${escapeHtml(reasons.map((x) => `${x.label}: ${x.detail || "—"}`).join("; "))}. Tap to open &amp; fix its tags.">✗ ${escapeHtml(reasons.map((x) => x.detail || x.label).join(" · "))}</button>`
      : "";
    // Comparable-mode: the lift's scaling ratio in THIS group; ratio 1 = the reference
    // ("étalon", the lift everything else is compared against — it stays the same).
    const ratio = ratioOf?.(r.name);
    // ONLY the group's single designated reference is tagged "étalon"; every other member
    // shows its ×ratio (incl. ×1 for an untuned member) — so a group can't show 4 étalons.
    const ratioChip = ratio == null ? ""
      : refEx != null && r.name === refEx
        ? ` <span class="bw-ratio bw-ratio-ref" title="Reference lift (étalon) — the others are scaled onto this one's curve.">★ étalon</span>`
        : ` <span class="bw-ratio" title="Scaling ratio vs the group's reference lift — this lift's load is divided by it to compare on one curve.">×${ratio}</span>`;
    return `<tr data-exrow="${escapeHtml(r.name)}"${hidden ? ' class="bw-row-hidden"' : ""}><td>` +
      `<span class="bw-ex-name" data-exname="${escapeHtml(r.name)}"><span class="caret">▸</span>${escapeHtml(r.name)}</span>` +
      ` <span class="bw-ex-code" title="Short code">${escapeHtml(codeFor(r.name))}</span>${originBadge(r.name)}${ratioChip}` +
      ` <button type="button" class="bw-moreinfo" data-moreinfoex="${escapeHtml(r.name)}" title="More info &amp; note-variation difficulty">ℹ</button>` +
      // Example-jump shows on EVERY lift; admin falls back to whoever's done it the most.
      ` <button type="button" class="bw-moreinfo bw-history" data-histex="${escapeHtml(r.name)}" title="See an example in this lift's workout history${lockedUsername() === null ? " — falls back to whoever's done it the most" : ""}">↗</button>` +
      // Flag a lift as "just a variation — review & merge into another" (a queue at the
      // top of the Index). The merge itself is done from the lift's ⓘ info card.
      ` <button type="button" class="bw-mergeflag${mergeReview.has(r.name) ? " is-on" : ""}" data-mergeflag="${escapeHtml(r.name)}" title="${mergeReview.has(r.name) ? "Flagged to merge — tap to unflag" : "Flag to review & merge into another lift"}">${mergeReview.has(r.name) ? "⤳ flagged" : "⤳ merge?"}</button>` +
      whyChip +
      // Force-show this lift app-wide despite the filter — the rare, TRACKED exception
      // (managed in the Great Filter's "kept exceptions" list), for when the tags are
      // right but you still want it shown.
      (hidden ? ` <button type="button" class="bw-keep${activeInclude.has(r.name) ? " is-on" : ""}" data-askeep="${escapeHtml(r.name)}" title="${activeInclude.has(r.name) ? "Kept as an exception — tap to drop back into the filter" : "Make an exception — always show this lift despite the filter (it stays tagged as-is)"}">${activeInclude.has(r.name) ? "✓ kept" : "＋ keep"}</button>` : "") +
      `</td>` +
      `<td class="num">${indexEditCell(r)}</td>` +
      `<td class="num">${r.count.toLocaleString()}</td></tr>`;
  };
  const table = (rs: IndexRow[], hidden: boolean, ratioOf?: (name: string) => number | null, refEx?: string | null) =>
    `<table class="data-table bw-table">${head}<tbody>${rs.map((r) => rowHtml(r, hidden, ratioOf, refEx)).join("")}</tbody></table>`;

  // "Review filtered-out": ONE place to see every lift the Great Filter is hiding
  // (greyed) and tap "＋ keep" to make an exception. Organised into the SAME groups as
  // the Index (by the current Group-by) so you can review by category, not one flat
  // wall. Only shown when a filter is hiding something; open states persist across the
  // re-render that "keep" triggers.
  const allHidden = activeSet ? rows.filter((r) => !activeSet!.has(r.name)) : [];
  // SECOND level inside each filtered-out group: split a sizeable group by another
  // dimension so e.g. 19 mixed "Tertiary" rejects read as labelled, colour-coded chunks
  // (Mobility / Balance / …) instead of one flat list. Discipline is the most telling lens
  // for rejects (it's usually WHY they're hidden); fall back to muscle when the primary
  // grouping IS discipline. Shown INLINE (not another collapsible) — the owner asked for
  // organisation, not more taps. Small groups / single-bucket splits stay flat.
  const reviewSubDim: IndexGroupMode = S.bwGroupMode === "discipline" ? "muscleGroup" : "discipline";
  const REVIEW_SUB_MIN = 8;
  const reviewGroupBody = (rs: IndexRow[]): string => {
    if (rs.length < REVIEW_SUB_MIN) return table(rs, true);
    const sb = indexBuckets(rs, reviewSubDim);
    if (sb.length < 2) return table(rs, true);
    return sb.map((s) =>
      `<div class="bw-review-sub" style="--sub-color:${s.color}">` +
      `<div class="bw-review-sub-h"><span class="bw-cat-dot" style="background:${s.color}"></span>` +
      `<span class="bw-cat-name">${escapeHtml(s.label)}</span> <span class="bw-cat-meta muted">${s.rows.length}</span></div>` +
      table(s.rows, true) +
      `</div>`,
    ).join("");
  };
  const reviewBody = (() => {
    if (allHidden.length < 2) return table(allHidden, true);
    const hb = indexBuckets(allHidden, S.bwGroupMode);
    if (hb.length < 2) return reviewGroupBody(allHidden); // one primary group → still split it inside
    return hb.map((b) =>
      `<details class="bw-cat bw-cat-sub bw-review-cat" data-cat="rv:${escapeHtml(b.key)}" style="--sub-color:${b.color}"${open("rv:" + b.key) ? " open" : ""}>` +
      `<summary class="bw-cat-summary">` +
      `<span class="bw-cat-dot" style="background:${b.color}"></span>` +
      `<span class="bw-cat-name">${escapeHtml(b.label)}</span>` +
      `<span class="bw-cat-meta muted">${b.rows.length}</span>` +
      `</summary>` +
      reviewGroupBody(b.rows) +
      `</details>`,
    ).join("");
  })();
  const reviewHtml = allHidden.length
    ? `<details class="bw-review" id="bwReview"${bwReviewOpen ? " open" : ""}>` +
      `<summary class="bw-review-sum">Review ${allHidden.length} filtered-out — tap “＋ keep” to make an exception</summary>` +
      reviewBody +
      `</details>`
    : "";

  // The merge-review queue: lifts the owner flagged "⤳ merge?". Listed by NAME (kept
  // even if the current filter hides them), each opening its info card (⊕ Combine /
  // ⇄ Compare) or unflagged with ✕. Sits at the very top of the Index when non-empty.
  const flaggedNames = [...mergeReview];
  const mergeFold = flaggedNames.length
    ? `<details class="bw-review bw-mergefold" open><summary class="bw-review-sum">⤳ Flagged to merge (${flaggedNames.length}) — tap a lift to open it &amp; ⊕ Combine / ⇄ Compare</summary>` +
      `<div class="bw-mergelist">` +
      flaggedNames.map((n) =>
        `<span class="bw-mergechip"><button type="button" class="bw-mergechip-open" data-moreinfoex="${escapeHtml(n)}" title="Open ${escapeHtml(n)} to merge it">${escapeHtml(displayName(n))} <span class="muted">${escapeHtml(codeFor(n))}</span></button>` +
        `<button type="button" class="bw-mergechip-x" data-mergeflag="${escapeHtml(n)}" title="Unflag" aria-label="Unflag">✕</button></span>`).join("") +
      `</div></details>`
    : "";

  // Live search (from the bottom bar): show a FLAT list of every lift whose name /
  // code / short-name matches, so you find it right here in the Index instead of
  // being thrown to the Analysis view. Skips the grouping + active-set machinery.
  if (bwSearchQuery) {
    const q = bwSearchQuery.toLowerCase();
    const matches = rows.filter(
      (r) => r.name.toLowerCase().includes(q) || codeFor(r.name).toLowerCase().includes(q) || shortFor(r.name).toLowerCase().includes(q),
    );
    els.bwGroups.innerHTML = matches.length
      ? `<div class="bw-search-results"><p class="bw-search-note muted">${matches.length} match${matches.length === 1 ? "" : "es"} for “${escapeHtml(bwSearchQuery)}”</p>${table(matches, false)}</div>`
      : `<p class="bw-search-note muted">No exercise matches “${escapeHtml(bwSearchQuery)}”.</p>`;
    return;
  }

  // Per-group app-wide filter: TWO independent buttons — "only these" and "hidden".
  // Both substantially filter the WHOLE app, so the active one glows red (strong
  // signal); white = off. They're mutually exclusive — turning one on clears the
  // other; tapping the active one turns it off (back to show-all). Members are read
  // from the group's rows in the DOM when clicked.
  const groupFilterToggle = (names: string[]): string => {
    const st = groupFilterState(names);
    return (
      `<span class="bw-cat-filter">` +
      `<button type="button" class="bw-filt bw-filt-only${st === "only" ? " is-on" : ""}" data-grpfilt="only" ` +
      `aria-pressed="${st === "only"}" title="Show ONLY this category across the whole app — tap to toggle">only these</button>` +
      `<button type="button" class="bw-filt bw-filt-hide${st === "hide" ? " is-on" : ""}" data-grpfilt="hide" ` +
      `aria-pressed="${st === "hide"}" title="Hide this category across the whole app — tap to toggle">hidden</button>` +
      `</span>`
    );
  };

  // Per-group sub-grouping: each TOP-LEVEL group can be sliced further by another
  // dimension (remembered per group). Strength still defaults to muscle-group.
  const subModeKey = (key: string) => `${S.bwGroupMode}:${key}`;
  // Big groups auto-organize so you never read a flat 100-row list: with NO explicit
  // per-group choice, a group over the threshold is sliced by MUSCLE (the natural
  // legs/chest/back split) — or, when you're ALREADY grouping by muscle, by DISCIPLINE
  // (strength vs calisthenics). Small groups stay flat. An explicit pick (incl. a sticky
  // "None") always wins — see onBwInputChange, which now persists "none" to override this.
  const autoSubMode = (rowCount: number): IndexGroupMode | "none" =>
    rowCount > IDX_AUTO_SUB_THRESHOLD ? (S.bwGroupMode === "muscleGroup" ? "discipline" : "muscleGroup") : "none";
  const subModeFor = (key: string, rowCount: number): string =>
    idxSubMode[subModeKey(key)] ?? autoSubMode(rowCount);
  const subSelHtml = (key: string, rowCount: number): string => {
    const explicit = idxSubMode[subModeKey(key)];
    const cur = explicit ?? autoSubMode(rowCount);
    const auto = explicit === undefined && cur !== "none"; // came from the size default, not a user pick
    const opts = `<option value="none"${cur === "none" ? " selected" : ""}>None</option>` +
      INDEX_GROUP_MODES.filter((m) => m.mode !== S.bwGroupMode)
        .map((m) => `<option value="${m.mode}"${cur === m.mode ? " selected" : ""}>${escapeHtml(m.label)}</option>`).join("");
    return `<div class="bw-substrat-bar">Sub-group by <select class="bw-substrat subtle-select" data-subkey="${escapeHtml(subModeKey(key))}">${opts}</select>` +
      (auto ? `<span class="bw-sub-auto" title="Auto-organised because this group is large — tap the menu to change">auto</span>` : "") +
      `</div>`;
  };
  // One group's collapsible <details> (coloured title + a "Sub-group by" selector, then
  // either its exercise table OR — when a sub-mode is chosen — nested sub-groups). The
  // active-set filter splits the flat table: active lifts stay; the rest go under "Show
  // hidden". `sub` = this is already a nested sub-group (no further nesting / selector).
  const bucketHtml = (b: IndexBucket, sub = false): string => {
    let sm = sub ? "none" : subModeFor(b.key, b.rows.length);
    // Don't add a pointless single sub-section: if the split yields <2 buckets, stay flat.
    if (sm !== "none" && indexBuckets(b.rows, sm as IndexGroupMode).length < 2) sm = "none";
    const shown = activeSet ? b.rows.filter((r) => activeSet!.has(r.name)) : b.rows;
    const hidden = activeSet ? b.rows.filter((r) => !activeSet!.has(r.name)) : [];
    const meta = activeSet
      ? `${shown.length}${hidden.length ? ` <span class="bw-cat-hidden">${hidden.length} hidden</span>` : ""}`
      : `${b.rows.length}`;
    // Comparable groups (top level): each row gets its scaling ratio + the étalon tag.
    const compRatios = !sub ? compRatioByGroup?.get(b.key) : undefined;
    const ratioOf = compRatios ? (name: string) => compRatios.get(name) ?? null : undefined;
    const refEx = compRatios ? groupReferenceEx(b.key) : null; // the ONE étalon for this group
    const flatBody = (shown.length
      ? table(shown, false, ratioOf, refEx)
      : `<p class="bw-allhidden muted">All ${b.rows.length} hidden by the active filter.</p>`) +
      (hidden.length
        ? `<details class="bw-hidden"><summary class="bw-hidden-sum">Show ${hidden.length} hidden by filter</summary>${table(hidden, true, ratioOf, refEx)}</details>`
        : "");
    const body = sm !== "none"
      ? indexBuckets(b.rows, sm as IndexGroupMode).map((s) => bucketHtml(s, true)).join("")
      : flatBody;
    return (
      `<details class="bw-cat${sub ? " bw-cat-sub" : ""}" data-cat="${escapeHtml(b.key)}"${sub ? ` style="--sub-color:${b.color}"` : ""}${open(b.key) ? " open" : ""}>` +
      `<summary class="bw-cat-summary">` +
      `<span class="bw-cat-dot" style="background:${b.color}"></span>` +
      `<span class="bw-cat-name">${escapeHtml(b.label)}</span>` +
      `<span class="bw-cat-meta muted">${meta}</span>` +
      groupFilterToggle(b.rows.map((r) => r.name)) +
      `</summary>` +
      (sub ? "" : subSelHtml(b.key, b.rows.length)) +
      body +
      `</details>`
    );
  };

  // In Discipline mode the two MAIN disciplines (Strength, Calisthenics) sit at the
  // top level — Strength gets the muscle/function sub-grouping — and everything else
  // nests as sub-groups under one "Other" header, since it's less central.
  if (S.bwGroupMode === "discipline") {
    const major = buckets.filter((b) => MAJOR_DISCIPLINES.includes(b.key as Discipline));
    const minor = buckets.filter((b) => !MAJOR_DISCIPLINES.includes(b.key as Discipline));
    const otherNames = new Set(minor.flatMap((b) => b.rows.map((r) => r.name)));
    const otherBlock = minor.length
      ? `<details class="bw-cat bw-cat-other" data-cat="__other"${open("__other") ? " open" : ""}>` +
        `<summary class="bw-cat-summary">` +
        `<span class="bw-cat-dot" style="background:#9aa1ac"></span>` +
        `<span class="bw-cat-name">Other</span>` +
        `<span class="bw-cat-meta muted">${otherNames.size} exercise${otherNames.size === 1 ? "" : "s"} · ${minor.length} groups</span>` +
        groupFilterToggle([...otherNames]) +
        `</summary>` +
        minor.map((b) => bucketHtml(b, true)).join("") +
        `</details>`
      : "";
    const majorHtml = major.map((b) => bucketHtml(b)).join("");
    els.bwGroups.innerHTML = mergeFold + reviewHtml + majorHtml + otherBlock;
    return;
  }

  els.bwGroups.innerHTML = mergeFold + reviewHtml + buckets.map((b) => bucketHtml(b)).join("");
}

/** The "Group by" picker above the Index exercise groups. */
function renderBwGroupBar(): void {
  const opts = INDEX_GROUP_MODES
    .map((m) => `<option value="${m.mode}"${m.mode === S.bwGroupMode ? " selected" : ""}>${escapeHtml(m.label)}</option>`)
    .join("");
  const editOpts = INDEX_EDIT_ATTRS
    .map((a) => `<option value="${a.attr}"${a.attr === indexEditAttr ? " selected" : ""}>${escapeHtml(a.label)}</option>`)
    .join("");
  els.bwGroupBar.innerHTML =
    `<label class="as-label">Group by <select id="bwGroupBy" class="subtle-select">${opts}</select></label>` +
    `<label class="as-label">Edit <select id="indexEditAttr" class="subtle-select">${editOpts}</select></label>`;
}

// ---- Edit athlete stats page ----
let statsEditUser = ""; // which athlete the editor is showing

/** Open the stats editor for one athlete (from the ✎ Edit button on the card). */
function openStatsEditor(username: string): void {
  statsEditUser = username;
  switchTopTab("statsedit");
}

/** Render the editable stats form for `statsEditUser` (defaults to the selected
 * athlete). Body-fat is five % inputs (95/50 band + average); a live nFFMI range
 * shows how the band propagates. */
// ---- "Live" coaching page -------------------------------------------------
// A training plan for the selected athlete: what to train today (by tier, most-
// stale first), antagonist superset pairings, warm-up guidance and watch-outs.
// Reuses the same decay model as the Maintenance section.

/** Per-athlete COACHING profile (owner-curated): training goals, injury cautions +
 * the areas to keep maintaining for them, and style notes/preferences. Keyed by a
 * lowercased name fragment matched against the username OR display name. */
interface CoachingProfile {
  goals?: string[];
  notes?: string[]; // style / preferences / constraints
  cautions?: string[]; // injuries / dangers
  maintain?: string[]; // areas to keep training to protect the cautions (muscle names auto-detected)
  /** Lean on antagonist supersets (e.g. tends to rush / cut rests short). */
  pushSupersets?: boolean;
  /** Explicit planned work for today (e.g. "2 sets of adductors"). Each item names a
   * muscle group; the working weight + warm-up are computed from recent strength. */
  planned?: PlannedWork[];
}
/** A planned block of work: N sets targeting a muscle group, with the working weight
 * and warm-up sized off the athlete's recent top set for that muscle. */
interface PlannedWork {
  muscle: MuscleGroup;
  sets: number;
  note?: string;
}
// Code-seeded defaults, matched by a name fragment. The owner's in-app edits (saved
// on device, keyed by exact username) take precedence over these.
const COACHING_SEED: Record<string, CoachingProfile> = {
  marija: {
    goals: [
      "Traps & grip — via the handstand progression",
      "Hip hinge — build it carefully (persistent hip-hinge issues)",
    ],
    notes: [
      "Very athletic — strong cardio & flexibility",
      "Tends to rush (rests too short) → use antagonist supersets so the pause is productive, not just short",
    ],
    cautions: ["Adductor pain", "Low back pain"],
    maintain: ["Adductors", "Hip flexors"],
    pushSupersets: true,
    planned: [{ muscle: "Adductors", sets: 2, note: "adductor care — keep it light" }],
  },
  indre: {
    notes: ["SQ height 19–20 (squat-rack holes)"],
  },
};
const COACHING_KEY = "colosseum.coaching.v1";
const coachingOverrides: Record<string, CoachingProfile> = loadJsonObject<Record<string, CoachingProfile>>(COACHING_KEY) ?? {};
function saveCoaching(): void { saveJson(COACHING_KEY, coachingOverrides); }
/** The code-seeded default for an athlete (matched on username / display name), or null. */
function coachingSeed(username: string): CoachingProfile | null {
  const keys = [username.toLowerCase(), nameForUsername(username).toLowerCase()];
  for (const [k, v] of Object.entries(COACHING_SEED)) if (keys.some((s) => s.includes(k))) return v;
  return null;
}
/** The effective coaching profile: the owner's on-device edit if any, else the seed. */
function coachingFor(username: string): CoachingProfile | null {
  return coachingOverrides[username] ?? coachingSeed(username);
}
/** Muscle groups named within an athlete's "maintain" lines (e.g. "Adductors"), so
 * their lifts can be surfaced for injury care. */
function maintainMusclesFor(coach: CoachingProfile | null): MuscleGroup[] {
  if (!coach?.maintain?.length) return [];
  const hay = coach.maintain.join(" ").toLowerCase();
  return MUSCLE_GROUPS.filter((m) => hay.includes(m.toLowerCase()));
}
/** The athlete's recent top weighted set on any lift hitting a muscle group — the
 * heaviest set logged for it in the last ~60 days. Used to size a warm-up off recent
 * strength. Returns null if no weighted set is on record. */
function recentTopSetForMuscle(username: string, muscle: MuscleGroup, todayD: number): { exercise: string; weight: number; reps: number; daysAgo: number } | null {
  let best: { exercise: string; weight: number; reps: number; day: number } | null = null;
  for (const r of computedRecords()) {
    if (r.username !== username || !r.date) continue;
    if (typeof r.weight !== "number" || !(r.weight > 0)) continue;
    const d = dayNumber(r.date);
    if (todayD - d > 60) continue; // only "recent" strength
    if (!mgsFor(r.exerciseName).includes(muscle)) continue;
    if (!best || r.weight > best.weight) best = { exercise: r.exerciseName, weight: r.weight, reps: r.reps ?? 0, day: d };
  }
  return best ? { exercise: best.exercise, weight: best.weight, reps: best.reps, daysAgo: todayD - best.day } : null;
}
/** Round a warm-up weight to a tidy increment (2.5 kg ≥ 20, else 1 kg). */
function tidyWarmupKg(kg: number): number {
  if (kg >= 20) return Math.round(kg / 2.5) * 2.5;
  return Math.max(1, Math.round(kg));
}
/** Lowercased goal/maintain keywords (≥3 chars), for goal-weighting the plan. */
function goalKeywords(coach: CoachingProfile | null): string[] {
  if (!coach) return [];
  const STOP = new Set(["the", "and", "via", "for", "with", "build", "carefully", "issues", "persistent", "related", "exercises", "good", "very"]);
  return [...new Set(
    [...(coach.goals ?? []), ...(coach.maintain ?? [])]
      .join(" ").toLowerCase().split(/[^a-z]+/)
      .filter((w) => w.length >= 3 && !STOP.has(w)),
  )];
}

/** Antagonist muscle-group pairs — opposing movers good to superset together. */
const ANTAGONIST_PAIRS: [MuscleGroup, MuscleGroup][] = [
  ["Chest", "Upper back"],
  ["Chest", "Lats"],
  ["Shoulders", "Lats"],
  ["Biceps", "Triceps"],
  ["Quads", "Hamstrings"],
  ["Abductors", "Adductors"],
  ["Lower back", "Core"],
];

interface LiveEx {
  name: string;
  tier: ExerciseTier;
  muscles: MuscleGroup[];
  sets: number;
  lastDay: number; // day-number of the most recent set (−Infinity = never)
  drop: number; // % below all-time peak (decayed-to-today)
  priority: number; // higher = needs work sooner
  goal?: boolean; // matches one of the athlete's goals (gets a ★ + priority boost)
}

/** Build each of the selected athlete's lifts with its tier, recency and decay. */
function liveExercises(username: string, todayD: number): LiveEx[] {
  const formula = currentFormula();
  const byEx = new Map<string, { days: Map<number, number>; sets: number; lastDay: number }>();
  for (const r of computedRecords()) {
    if (r.username !== username || !r.date) continue;
    const d = dayNumber(r.date);
    let e = byEx.get(r.exerciseName);
    if (!e) { e = { days: new Map(), sets: 0, lastDay: -Infinity }; byEx.set(r.exerciseName, e); }
    e.sets++;
    e.lastDay = Math.max(e.lastDay, d);
    if (addedWeight1RM(r, formula) !== null) {
      const eff = estimate1RM(r.weight, r.reps, formula);
      if (eff !== null) e.days.set(d, Math.max(e.days.get(d) ?? -Infinity, eff));
    }
  }
  // Goal-weighting: a lift whose NAME or MUSCLE matches a goal/maintain keyword gets
  // a big priority boost, so the athlete's goals surface first (their answer).
  const kw = goalKeywords(coachingFor(username));
  const matchesGoal = (name: string, muscles: MuscleGroup[]): boolean => {
    if (!kw.length) return false;
    const hay = (name + " " + muscles.join(" ")).toLowerCase();
    return kw.some((k) => hay.includes(k));
  };
  const out: LiveEx[] = [];
  for (const [name, e] of byEx) {
    let drop = 0;
    if (e.days.size) {
      const pts = [...e.days.entries()].map(([d, y]) => ({ x: d * MS_PER_DAY_RIR, y }));
      const peak = Math.max(...pts.map((p) => p.y));
      const series = decayingStrengthPoints(pts);
      const cur = series.length ? series[series.length - 1]!.y : peak;
      drop = peak > 0 ? Math.max(0, ((peak - cur) / peak) * 100) : 0;
    }
    const daysAgo = Number.isFinite(e.lastDay) ? todayD - e.lastDay : 999;
    const muscles = mgsFor(name);
    const goal = matchesGoal(name, muscles);
    // Needs-work score: slipped-from-peak + time since trained (capped) + a big GOAL
    // boost so goal-relevant lifts lead the plan.
    const priority = drop + Math.min(60, daysAgo) * 0.5 + (goal ? 100 : 0);
    out.push({ name, tier: tiersFor(name)[0] ?? "main", muscles, sets: e.sets, lastDay: e.lastDay, drop, priority, goal });
  }
  return out;
}

