    const idx = Math.max(0, Math.min(romKeys.length - 1, parseInt(sl.value, 10) || 0));
    setNoteVecDim(ex, note, "rom", romKeys[idx]!);
    const vec = { ...rNote(fam, note).vec, ...noteVecOverride(ex, note) };
